import fs from "fs";
import path from "path";

function bundleAllInOne() {
  const distDir = path.join(process.cwd(), "dist");
  const assetsDir = path.join(distDir, "assets");
  
  if (!fs.existsSync(distDir)) {
    console.error("Dist directory does not exist! Please compile the app first.");
    return;
  }
  
  // Find the CSS and JS files in assets
  const files = fs.readdirSync(assetsDir);
  const jsFile = files.find(f => f.endsWith(".js"));
  const cssFile = files.find(f => f.endsWith(".css"));
  
  if (!jsFile || !cssFile) {
    console.error("Failed to locate compiled JS or CSS files in /dist/assets!");
    return;
  }
  
  console.log(`Found JS file: ${jsFile}`);
  console.log(`Found CSS file: ${cssFile}`);
  
  // Read code content
  let indexHtml = fs.readFileSync(path.join(distDir, "index.html"), "utf-8");
  const jsCode = fs.readFileSync(path.join(assetsDir, jsFile), "utf-8");
  const cssCode = fs.readFileSync(path.join(assetsDir, cssFile), "utf-8");
  
  // Clean up existing link and script tags referring to assets
  // We match standard tags generated by Vite:
  // e.g., <link rel="stylesheet" crossorigin href="/assets/index-*.css">
  // and <script type="module" crossorigin src="/assets/index-*.js"></script>
  let mergedHtml = indexHtml;
  
  // Replace css link with inlined stylesheet
  const cssLinkRegex = /<link\s+rel=["']stylesheet["']\s+crossorigin\s+href=["']\/assets\/index-.*?\.css["']\s*\/?>/gi;
  const inlinedCss = `<style>\n${cssCode}\n</style>`;
  if (cssLinkRegex.test(mergedHtml)) {
    mergedHtml = mergedHtml.replace(cssLinkRegex, inlinedCss);
  } else {
    // General fallback replacement if vite output structure slightly varies
    mergedHtml = mergedHtml.replace("</head>", `${inlinedCss}\n</head>`);
  }
  
  // Replace js tag with inlined script (without type="module" constraint if needed for blogger compatibility, though keeping it can also be fine. Inlining it cleanly is best)
  const jsScriptRegex = /<script\s+type=["']module["']\s+crossorigin\s+src=["']\/assets\/index-.*?\.js["']\s*><\/script>/gi;
  const inlinedJs = `<script type="module">\n${jsCode}\n</script>`;
  if (jsScriptRegex.test(mergedHtml)) {
    mergedHtml = mergedHtml.replace(jsScriptRegex, inlinedJs);
  } else {
    // General fallback replacement
    mergedHtml = mergedHtml.replace("</body>", `${inlinedJs}\n</body>`);
  }
  
  // Clean potential absolute assets if any are present (like /assets) or canonical paths to ensure self-containment
  mergedHtml = mergedHtml.replace(/href="\/assets\//g, 'href="');
  mergedHtml = mergedHtml.replace(/src="\/assets\//g, 'src="');

  // Save as .html file and .txt version
  const outHtmlPath = path.join(process.cwd(), "world_cup_2026_predictor_blogger.html");
  const outTxtPath = path.join(process.cwd(), "world_cup_2026_predictor_blogger.txt");
  
  fs.writeFileSync(outHtmlPath, mergedHtml);
  fs.writeFileSync(outTxtPath, mergedHtml);
  
  console.log(`Successfully merged assets! Standalone file created at: \n- ${outHtmlPath}\n- ${outTxtPath}`);
}

bundleAllInOne();
